import { workflow, node, trigger } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const setNode = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'Set Sample Fields',
    parameters: {
      assignments: {
        assignments: [
          {
            id: 'field-1',
            name: 'sample_text',
            value: 'Hello, world!',
            type: 'string'
          },
          {
            id: 'field-2',
            name: 'sample_number',
            value: 42,
            type: 'number'
          },
          {
            id: 'field-3',
            name: 'sample_flag',
            value: true,
            type: 'boolean'
          }
        ]
      }
    }
  }
});

export default workflow('manual-set-test', 'Manual Trigger - Set Node Test')
  .add(manualTrigger)
  .to(setNode);
